+    #[test]
+    fn default_config_cap_hierarchy() {
+        let c = FlowControlConfig::default();
+        assert!(c.input_soft_cap_bytes < c.input_hard_cap_bytes);
+        assert!(c.output_soft_cap_bytes < c.output_hard_cap_bytes);
